const ALL_QUESTIONS = [
  {id:1,category:"Service Knowledge",service:"Weekly Lawn Maintenance",type:"mc",question:"What happens to grass clippings under the Nutrient Standard mowing plan?",options:["They are bagged and removed from the property","They are finely mulched and returned to the lawn","They are composted on-site in a designated area","The client chooses each visit"],answer:1,explanation:"Nutrient Standard mulches clippings and returns them to the lawn, recycling nutrients back into the soil."},
  {id:2,category:"Tier Differences",service:"Weekly Lawn Maintenance",type:"mc",question:"What is the key upgrade a client gets with Pristine Standard mowing over Nutrient Standard?",options:["Twice-weekly mowing instead of weekly","Bagging and removal of all grass clippings","Fertilizer application included with each visit","Edging of all garden beds"],answer:1,explanation:"Pristine Standard bags and removes all clippings for a consistently clean appearance. Everything else is the same."},
  {id:3,category:"Service Knowledge",service:"Weekly Lawn Maintenance",type:"mc",question:"Which of the following is included in BOTH Nutrient Standard and Pristine Standard mowing?",options:["Bagging of clippings","Fertilizer application","String trimming around edges, obstacles, and beds + blowing hard surfaces","Garden bed weeding"],answer:2,explanation:"Both tiers include professional mowing, string trimming around edges/obstacles/beds, and blowing of hard surfaces."},
  {id:4,category:"Service Knowledge",service:"Weekly Lawn Maintenance",type:"mc",question:"Does Nutrient Standard mowing leave messy piles of grass on the lawn?",options:["Yes — clippings are left in piles","No — clippings are finely mulched so they break down quickly and are barely visible","Only during peak growing season","It depends on the lawn size"],answer:1,explanation:"Clippings are finely mulched, not left in piles. They break down quickly and feed the soil."},
  {id:5,category:"Scenario",service:"Weekly Lawn Maintenance",type:"scenario",question:"A client says: \"I don't want grass clippings left on my lawn — it looks messy. But I also don't want to pay too much. What are my options?\"",answer:"Explain both tiers: Nutrient Standard mulches clippings back into the lawn (actually great for lawn health — feeds the soil naturally), and the clippings are finely mulched so they break down quickly — not messy piles at all. But if a consistently clean look matters most, Pristine Standard bags and removes all clippings every visit. Most people are surprised how clean Nutrient actually looks, so it might be worth trying first.",keyPoints:["Explain Nutrient Standard returns mulched clippings (good for lawn health)","Explain Pristine Standard bags and removes everything","Reassure that mulched clippings break down quickly — not messy","Help them weigh cost vs appearance preference"]},
  {id:6,category:"Scenario",service:"Weekly Lawn Maintenance",type:"scenario",question:"A client asks: \"Why should I pay more for Pristine mowing? What do I actually get?\"",answer:"With Pristine, all grass clippings are bagged and removed from the property every visit. The result is a consistently clean, manicured appearance — no clippings visible at all. Nutrient Standard is great too — it mulches the clippings back into the lawn which is actually better for soil health. But some people just prefer that perfectly clean look every week, and that's what Pristine delivers.",keyPoints:["Pristine bags and removes all clippings","Consistently clean, manicured appearance","Nutrient is good for lawn health but some prefer the cleaner look","Frame both as valid choices, not upselling"]},
  {id:7,category:"Service Knowledge",service:"Weekly Lawn Maintenance",type:"mc",question:"What does 'Nutrient Standard' mean in the context of Amigos' services?",options:["We apply fertilizer nutrients during the service","Organic material is returned to the soil/lawn to recycle nutrients naturally","We use only organic products","It's the premium tier with extra treatments"],answer:1,explanation:"Nutrient Standard philosophy: organic material (clippings, leaves, debris) is returned to the soil to recycle nutrients naturally."},
  {id:8,category:"Service Knowledge",service:"Weekly Lawn Maintenance",type:"mc",question:"What does 'Pristine Standard' mean across Amigos services?",options:["We use the highest quality materials","All collected material is completely hauled away for a clean appearance","We visit twice as often","Chemical treatments are included"],answer:1,explanation:"Pristine Standard: all material is hauled away for a perfectly clean appearance."},
  {id:9,category:"Tier Differences",service:"Weekly Lawn Maintenance",type:"mc",question:"Besides clipping handling, is there ANY other difference between Nutrient and Pristine mowing?",options:["Pristine includes more trimming detail","Pristine crews spend more time on-site","No — identical service, the only difference is clippings are bagged vs mulched","Pristine includes a monthly deep-clean"],answer:2,explanation:"Identical service in every way — the only difference is what happens to the clippings."},
  {id:10,category:"Service Knowledge",service:"Weekly Lawn Maintenance",type:"mc",question:"Does Weekly Lawn Maintenance include any lawn treatments like fertilizer or weed control?",options:["Yes — fertilizer is applied monthly","Yes — weed control is included with Pristine","No — it's mowing, string trimming, and blowing only","Only if the client adds it to their plan"],answer:2,explanation:"Weekly Lawn Maintenance is mowing, string trimming, and blowing. No fertilizer, weed control, or other treatments."},
  {id:11,category:"Scenario",service:"Weekly Lawn Maintenance",type:"scenario",question:"A client asks: \"Does your mowing service include edging along my flower beds and blowing off my driveway?\"",answer:"Yes! Both our Nutrient and Pristine mowing plans include string trimming around all edges, obstacles, and beds, plus blowing of all hard surfaces like your driveway and walkways. That's standard on every visit.",keyPoints:["String trimming around edges, obstacles, and beds is included","Blowing of hard surfaces is included","Both tiers include this — it's not an upgrade feature","Confirm clearly and confidently"]},
  {id:12,category:"Scenario",service:"Weekly Lawn Maintenance",type:"scenario",question:"A client says: \"I heard returning grass clippings to the lawn is bad — doesn't it cause thatch?\"",answer:"That's actually a common misconception. Finely mulched grass clippings break down quickly and return nutrients to the soil — they don't contribute to thatch buildup. It's actually one of the best things you can do for your lawn's health. That said, if you just prefer a cleaner look without any clippings visible, our Pristine Standard bags everything. Both approaches work great — it really comes down to preference.",keyPoints:["Address the misconception directly — mulched clippings don't cause thatch","Clippings break down quickly and feed the soil","Position Nutrient as the healthy choice","Offer Pristine as the preference-based alternative"]},
  {id:13,category:"Service Knowledge",service:"Weekly Lawn Maintenance",type:"mc",question:"What is NOT included in Weekly Lawn Maintenance?",options:["String trimming around obstacles","Blowing hard surfaces","Garden bed weeding or fertilizer application","Professional mowing of all turf areas"],answer:2,explanation:"Mowing plans include mowing, string trimming, and blowing. Bed weeding, fertilizer, and treatments are separate."},
  {id:14,category:"Tier Differences",service:"Weekly Lawn Maintenance",type:"mc",question:"If a client is environmentally conscious and wants the healthiest approach for their lawn, which tier should you recommend?",options:["Pristine Standard — it keeps the lawn cleanest","Nutrient Standard — returning clippings feeds the soil naturally","Either — they're identical for lawn health","Neither — they need a fertilizer program"],answer:1,explanation:"Nutrient Standard is the eco-friendly, lawn-health-first choice."},
  {id:15,category:"Scenario",service:"Weekly Lawn Maintenance",type:"scenario",question:"A client asks: \"Do you do any kind of lawn treatments — like fertilizer, weed control, or grub prevention?\"",answer:"Currently our lawn health services focus on aeration and overseeding — two of the best things you can do for long-term lawn health. We don't currently offer chemical treatment programs like fertilizer, weed control, or grub prevention. For those you'd want a lawn care treatment company. But our aeration loosens the soil for better root growth, and overseeding thickens the turf which naturally helps crowd out weeds.",keyPoints:["We offer aeration and overseeding","We do NOT offer fertilizer, weed control, or pest treatments","Be honest about what we don't offer","Redirect to what we DO offer"]},
  {id:16,category:"Service Knowledge",service:"Weekly Lawn Maintenance",type:"mc",question:"Weekly Lawn Maintenance runs from approximately when to when?",options:["March through October","April through November","May through September","Year-round"],answer:1,explanation:"Mowing runs approximately April through November."},
  {id:17,category:"Service Knowledge",service:"Weekly Lawn Maintenance",type:"mc",question:"How often does the mowing crew visit during the active season?",options:["Bi-weekly","Weekly","Twice a week","Monthly"],answer:1,explanation:"Weekly visits, weather permitting."},
  {id:18,category:"Tier Differences",service:"Weekly Lawn Maintenance",type:"mc",question:"A client on Nutrient Standard asks about switching to Pristine. Is this a scope change or approach change?",options:["Completely different service with different crew procedures","Same visit — the only change is clippings are bagged instead of mulched","Pristine includes additional services like fertilizer","You can't switch mid-season"],answer:1,explanation:"Same mowing visit — string trimming, edging, blowing all stay the same. Only clipping handling changes."},
  {id:19,category:"Service Knowledge",service:"Spring Cleanup",type:"mc",question:"What does a Spring Cleanup include?",options:["Leaves, sticks, and debris cleared from lawn and beds","Full property cleanup including trimming, pruning, and mulch","Only lawn debris removal — beds are not touched","Power washing of hardscapes"],answer:0,explanation:"Clears leaves, sticks, and debris from lawn and beds — early-season reset."},
  {id:20,category:"Tier Differences",service:"Spring Cleanup",type:"mc",question:"What is the difference between Nutrient Standard and Pristine Standard Spring Cleanup?",options:["Nutrient is lawn only; Pristine includes beds","Nutrient returns shredded material to soil; Pristine hauls everything away","Pristine includes trimming and pruning","Pristine uses organic products"],answer:1,explanation:"Same scope. Nutrient shreds and returns to soil. Pristine hauls away."},
  {id:21,category:"Service Knowledge",service:"Spring Cleanup",type:"mc",question:"Which of the following is NOT included in a Spring Cleanup?",options:["Clearing debris from lawn","Clearing debris from beds","Trimming, pruning, bed edging, or mulch","Shredding organic material (Nutrient Standard)"],answer:2,explanation:"Does NOT include trimming, pruning, bed edging, or mulch."},
  {id:22,category:"Scenario",service:"Spring Cleanup",type:"scenario",question:"A client asks: \"Can you do my spring cleanup and also trim my bushes and put down mulch at the same time?\"",answer:"Spring Cleanup is specifically debris clearing — leaves, sticks, winter leftovers. It doesn't include trimming, pruning, bed edging, or mulch. Those are separate services that happen later in the season. Cleanup comes first, then beds and mulch, then trimming. I can quote everything separately so you know the full plan.",keyPoints:["Cleanup does NOT include trimming, pruning, edging, or mulch","These are separate services","Offer to quote each separately","Common question — don't make them feel bad"]},
  {id:23,category:"Service Knowledge",service:"Spring Cleanup",type:"mc",question:"Spring Cleanup is what type of service?",options:["Recurring (weekly)","One-time","Add-on to mowing","Monthly"],answer:1,explanation:"One-time service performed once each spring."},
  {id:24,category:"Scenario",service:"Spring Cleanup",type:"scenario",question:"A client asks: \"What does Nutrient Standard mean for spring cleanup? Do you put fertilizer down?\"",answer:"No fertilizer — Nutrient Standard means we shred all the organic debris and return it to your soil rather than hauling it away. The shredded material breaks down and naturally feeds your soil. It's the eco-friendly approach. If you'd rather have everything completely removed, that's Pristine Standard — same cleanup, we just haul everything away.",keyPoints:["Nutrient does NOT mean fertilizer","Material shredded and returned to soil","Natural nutrient recycling","Pristine hauls away instead","Same scope either way"]},
  {id:25,category:"Tier Differences",service:"Spring Cleanup",type:"mc",question:"A client who wants their property perfectly clean after spring cleanup should choose which tier?",options:["Nutrient Standard — it shreds debris finer","Pristine Standard — all material is hauled away","Either — both achieve the same result","They need a separate service"],answer:1,explanation:"Pristine hauls everything away for a perfectly clean appearance."},
  {id:26,category:"Service Knowledge",service:"Spring Cleanup",type:"mc",question:"Does Spring Cleanup require an active mowing plan?",options:["Yes — add-on to mowing","No — standalone one-time service","Only for Pristine Standard","Only for Property Plan clients"],answer:1,explanation:"Standalone — no mowing plan required."},
  {id:27,category:"Scenario",service:"Spring Cleanup",type:"scenario",question:"A client says: \"My yard is a mess from winter. I need everything done — cleanup, beds, bushes, mulch. Where do I start?\"",answer:"Start with Spring Cleanup to clear all the winter debris. That's your clean slate. From there: bed work and mulch come next, bush trimming later once things have had their spring growth. I can map out the full plan and quote each service so you know what's coming.",keyPoints:["Start with Spring Cleanup","Clean baseline for everything else","Then beds, mulch, trimming in order","Offer to plan and quote everything"]},
  {id:28,category:"Tier Differences",service:"Spring Cleanup",type:"mc",question:"A client who cares about soil health should choose which Spring Cleanup tier?",options:["Pristine — cleaner means healthier","Nutrient Standard — shredded material feeds soil naturally","Doesn't matter — no impact on soil","Neither — need separate soil treatment"],answer:1,explanation:"Nutrient Standard shreds debris and returns it to soil, naturally recycling nutrients."},
  {id:29,category:"Service Knowledge",service:"Spring Cleanup",type:"mc",question:"The Nutrient vs Pristine naming is used for which services?",options:["Only mowing","Mowing, spring cleanup, and one-time property cleanup","All services","Only winter services"],answer:1,explanation:"Used for services where material is either returned to soil or hauled away."},
  {id:30,category:"Service Knowledge",service:"Spring Cleanup",type:"mc",question:"Spring Cleanup addresses which season's leftover debris?",options:["Summer","Fall","Winter","All seasons"],answer:2,explanation:"Clears winter's leftover debris before lawn starts growing."},
  {id:31,category:"Service Knowledge",service:"Aeration",type:"mc",question:"What is lawn aeration?",options:["Spraying liquid nutrients into the soil","Mechanical core aeration — pulling small plugs of soil to loosen compacted ground","Applying a chemical soil loosener","Raking to remove thatch"],answer:1,explanation:"Mechanical core aeration — pulling soil plugs to relieve compaction."},
  {id:32,category:"Service Knowledge",service:"Overseeding",type:"mc",question:"What does overseeding do?",options:["Replaces the entire lawn","Thickens existing turf by spreading seed over the current lawn","Kills weeds and replants","Applies seed-and-fertilizer combo"],answer:1,explanation:"Thickens existing turf by spreading new seed."},
  {id:33,category:"Service Knowledge",service:"Overseeding",type:"mc",question:"What does overseeding NOT do?",options:["Improve lawn density","Fill large bare patches or severely damaged areas","Help crowd out weeds","Strengthen root system"],answer:1,explanation:"Does NOT fill large bare or severely damaged areas — needs hydroseeding or renovation."},
  {id:34,category:"Service Knowledge",service:"Aeration",type:"mc",question:"Why is aeration beneficial?",options:["Kills weeds by exposing roots","Relieves soil compaction so air, water, and nutrients reach roots better","Adds fertilizer to root zone","Removes excess thatch"],answer:1,explanation:"Relieves compaction, improving air/water/nutrient flow to roots."},
  {id:35,category:"Service Knowledge",service:"Aeration",type:"mc",question:"Are Spring Aeration and Spring Overseeding the same service?",options:["Yes — always bundled","No — separate services commonly paired","Aeration includes overseeding","Overseeding includes aeration"],answer:1,explanation:"Separate services, commonly paired but quoted individually."},
  {id:36,category:"Scenario",service:"Aeration",type:"scenario",question:"A client asks: \"What's aeration? Why would I need it?\"",answer:"Aeration is where we run a machine across your lawn that pulls small plugs of soil out of the ground. Over time, soil gets compacted and it's hard for air, water, and nutrients to reach the roots. Aeration opens that up so your lawn can breathe and grow stronger. It's one of the best things you can do for lawn health.",keyPoints:["Explain physically — machine pulls soil plugs","Relieves compaction","Better air, water, nutrient flow","Keep it simple and relatable"]},
  {id:37,category:"Scenario",service:"Overseeding",type:"scenario",question:"A client says: \"I have a big bare patch — can overseeding fix it?\"",answer:"Overseeding thickens existing turf — great for thin areas. But for a big bare patch, overseeding alone won't be enough. That would need hydroseeding or another restoration method. I'd want to take a look and recommend the right approach.",keyPoints:["Overseeding thickens existing turf","Not for large bare patches","Needs hydroseeding or renovation","Be honest, offer to assess"]},
  {id:38,category:"Scenario",service:"Aeration",type:"scenario",question:"A client asks: \"Should I do aeration in spring or fall?\"",answer:"Fall is generally the best time in Illinois — less weed competition and the grass has fall and spring to establish before summer heat. Spring works too, but overseeding in spring is trickier because weeds germinate at the same time. If you're choosing one, go fall. Both is ideal for maximum health.",keyPoints:["Fall is the stronger recommendation","Less weed competition in fall","Spring seeding competes with weeds","Both is ideal, fall is priority"]},
  {id:39,category:"Service Knowledge",service:"Overseeding",type:"mc",question:"Why is spring overseeding trickier than fall?",options:["Soil is too cold","Weeds germinate at the same time, and crabgrass preventer can block grass seed","Spring storms wash away seed","Not enough sunlight"],answer:1,explanation:"Spring overseeding competes with weeds, and pre-emergent can block grass seed."},
  {id:40,category:"Service Knowledge",service:"Aeration",type:"mc",question:"Amigos offers aeration in which seasons?",options:["Spring only","Fall only","Both spring and fall","Year-round"],answer:2,explanation:"Both Spring Aeration and Fall Aeration are offered."},
  {id:41,category:"Service Knowledge",service:"Overseeding",type:"mc",question:"Is seed material included in overseeding or does the client buy it?",options:["Client provides their own","Seed cost is embedded — included","Billed as separate materials charge","Only included with fall"],answer:1,explanation:"Seed cost is embedded in the price."},
  {id:42,category:"Service Knowledge",service:"Aeration",type:"mc",question:"What does the lawn look like right after aeration?",options:["Perfectly smooth","Small soil plugs on the surface — break down in 1-2 weeks","Torn up and needs replanting","Large visible holes"],answer:1,explanation:"Small soil plugs left on surface, break down naturally in a couple weeks."},
  {id:43,category:"Scenario",service:"Aeration",type:"scenario",question:"A client says: \"We just moved in and the lawn feels rock hard.\"",answer:"That sounds like soil compaction — really common, especially with new construction. Aeration pulls small plugs of soil to open everything up so air, water, and nutrients can reach the roots again. I'd recommend pairing it with overseeding to thicken the turf. Fall is ideal, but spring works too.",keyPoints:["Identify compaction","Recommend aeration","Suggest pairing with overseeding","Mention fall as ideal"]},
  {id:44,category:"Service Knowledge",service:"Aeration",type:"mc",question:"Do aeration and overseeding require a mowing plan?",options:["Yes — both require mowing","No — both are standalone","Only overseeding requires mowing","Only if on a Property Plan"],answer:1,explanation:"Both are standalone one-time services."},
  {id:45,category:"Scenario",service:"Overseeding",type:"scenario",question:"A client says: \"I want to put down crabgrass preventer AND overseed this spring.\"",answer:"Crabgrass preventer works by stopping seeds from germinating — including grass seed. So you generally have to choose one or the other in spring. If you overseed, skip the pre-emergent. If crabgrass is the bigger concern, skip spring seeding and we'll do fall overseeding instead — which is actually the better time for it.",keyPoints:["Pre-emergent blocks grass seed too","Can't do both simultaneously","Pick one or defer seeding to fall","Fall is better for overseeding anyway"]},
  {id:46,category:"Service Knowledge",service:"Aeration",type:"mc",question:"What category do Aeration and Overseeding fall under?",options:["Recurring Lawn Maintenance","Lawn Health","Seasonal Cleanups","Garden Bed Maintenance"],answer:1,explanation:"Both fall under 'Lawn Health.'"},
  {id:47,category:"Service Knowledge",service:"Aeration",type:"mc",question:"Aeration and overseeding are what type of service?",options:["Recurring","One-time","Add-on to mowing","Monthly"],answer:1,explanation:"Both are one-time services."},
  {id:48,category:"Service Knowledge",service:"Overseeding",type:"mc",question:"For severely damaged lawns, what does Amigos recommend instead of overseeding?",options:["More frequent overseeding","Hydroseeding or other renovation (not currently offered by Amigos)","Extra fertilizer","Heavy aeration"],answer:1,explanation:"Severely damaged lawns need hydroseeding or renovation, which Amigos doesn't currently offer."},
  {id:49,category:"Service Knowledge",service:"Garden Bed Maintenance",type:"mc",question:"Garden Bed Maintenance plans are add-ons to which service?",options:["Spring Cleanup","Mulch Installation","An active mowing plan","Any recurring service"],answer:2,explanation:"Both plans require an active mowing plan."},
  {id:50,category:"Tier Differences",service:"Garden Bed Maintenance",type:"mc",question:"What method does the Clean Look Plan use to control weeds?",options:["Hand-pulling from root","String trimmers for mechanical weed control (roots stay intact)","Chemical herbicide","Preen weed preventer"],answer:1,explanation:"Clean Look uses string trimmers — mechanical trim only, roots remain."},
  {id:51,category:"Tier Differences",service:"Garden Bed Maintenance",type:"mc",question:"What method does the Estate Detail Plan use?",options:["String trimmers only","Chemical herbicide spray","Hand-pulled weeding plus Preen weed preventer","Full bed replacement"],answer:2,explanation:"Estate Detail = hand-pulled weeding + Preen weed preventer."},
  {id:52,category:"Service Knowledge",service:"Garden Bed Maintenance",type:"mc",question:"What does Preen weed preventer do?",options:["Kills existing weeds on contact","Prevents new weeds from sprouting but does NOT eliminate existing ones","Fertilizes beds","Blocks all plant growth"],answer:1,explanation:"Prevents new weeds from sprouting — doesn't kill existing ones."},
  {id:53,category:"Scenario",service:"Garden Bed Maintenance",type:"scenario",question:"A client asks: \"What's the difference between your two bed plans?\"",answer:"Clean Look is more affordable — we use string trimmers to knock down visible weed growth. It's mechanical only, so roots stay and weeds regrow, but beds look neat. Estate Detail is our premium plan — we hand-pull weeds from the root and apply Preen, which stops new weeds from sprouting. More thorough and keeps beds cleaner long-term. Both require a mowing plan.",keyPoints:["Clean Look: trimmer, roots stay, affordable","Estate Detail: hand-pull + Preen, more thorough","Help choose based on budget and expectations","Both require mowing plan"]},
  {id:54,category:"Tier Differences",service:"Garden Bed Maintenance",type:"mc",question:"Why do weeds grow back faster on Clean Look than Estate Detail?",options:["Clean Look uses less effective products","Clean Look only cuts at surface — roots remain to regrow","Estate Detail visits more often","Clean Look beds don't get mulch"],answer:1,explanation:"Clean Look trims mechanically but roots remain. Estate Detail removes roots and prevents new growth."},
  {id:55,category:"Scenario",service:"Garden Bed Maintenance",type:"scenario",question:"Client says Clean Look isn't keeping up with weeds. What do you recommend?",answer:"If weeds are exceeding Clean Look's capacity, I'd recommend a Bed Reset first to bring beds back to baseline. Then either continue Clean Look from that fresh start, or upgrade to Estate Detail which hand-pulls from the root and applies Preen to prevent regrowth. Estate Detail does a much better job long-term.",keyPoints:["Acknowledge Clean Look's limits","Bed Reset first for clean baseline","Then upgrade to Estate Detail or restart Clean Look","Estate Detail is more thorough"]},
  {id:56,category:"Service Knowledge",service:"Garden Bed Maintenance",type:"mc",question:"Does Estate Detail require clients to schedule individual weeding visits?",options:["Yes — call each time","No — care is built into routine automatically spring through fall","Only first visit needs scheduling","Schedule bi-weekly via app"],answer:1,explanation:"No scheduling needed — care is built into the routine."},
  {id:57,category:"Tier Differences",service:"Garden Bed Maintenance",type:"mc",question:"Which plan includes Preen weed preventer?",options:["Clean Look Plan","Estate Detail Plan","Both plans","Neither"],answer:1,explanation:"Only Estate Detail includes Preen."},
  {id:58,category:"Scenario",service:"Garden Bed Maintenance",type:"scenario",question:"Client wants Estate Detail but doesn't have a mowing plan.",answer:"Both bed plans require an active mowing plan — the care is built into our weekly visits. Without that weekly presence, we can't deliver consistent bed maintenance. But we have standalone options: one-time weeding visits, bed resets, and mulch don't require a mowing plan at all. Or we could look at getting you on a mowing plan too.",keyPoints:["Both plans require mowing plan","Offer standalone alternatives","Don't just say no — provide solutions","Could pitch mowing plan as a package"]},
  {id:59,category:"Tier Differences",service:"Garden Bed Maintenance",type:"mc",question:"Which statement best describes Clean Look vs Estate Detail?",options:["Clean Look is cosmetic maintenance; Estate Detail is thorough weed management","Clean Look is monthly; Estate Detail is weekly","Clean Look is for small beds; Estate Detail is for large","Clean Look is manual; Estate Detail uses machinery"],answer:0,explanation:"Clean Look = cosmetic (trims visible weeds). Estate Detail = thorough (removes roots + prevents regrowth)."},
  {id:60,category:"Service Knowledge",service:"Garden Bed Maintenance",type:"mc",question:"What should happen before starting a bed maintenance plan if beds are overgrown?",options:["Start the plan immediately","A one-time Bed Reset to bring beds to baseline first","Refuse service until manageable","Charge double for first month"],answer:1,explanation:"Bed Reset brings beds to a clean baseline, then maintenance keeps them there."},
  {id:61,category:"Scenario",service:"Garden Bed Maintenance",type:"scenario",question:"Budget-conscious client asks: \"Is Clean Look even worth it if weeds grow back?\"",answer:"Clean Look keeps beds looking neat between visits — controls visible growth so things don't get out of hand. Like mowing — the grass keeps growing but we keep it looking great. If you want more permanent weed control, Estate Detail pulls from the root and prevents new ones. But for most people who want neat-looking beds, Clean Look gets the job done.",keyPoints:["Clean Look controls visible growth — neat appearance","Compare to mowing — ongoing maintenance","Estate Detail for permanent control","Don't undersell Clean Look"]},
  {id:62,category:"Service Knowledge",service:"Garden Bed Maintenance",type:"mc",question:"What is Clean Look Plan's main limitation?",options:["Only covers front yard","If weed growth exceeds capacity, upgrade or reset may be required","Only for small beds","Doesn't include trimming"],answer:1,explanation:"If weed growth exceeds what Clean Look can manage, an upgrade or reset may be needed."},
  {id:63,category:"Scenario",service:"Garden Bed Maintenance",type:"scenario",question:"Client doesn't want chemicals. Can they still do Estate Detail without Preen?",answer:"Preen is actually a pre-emergent — prevents seeds from germinating, not a harsh chemical. But if you'd rather skip it, we can still do the hand-pulling portion. You could also consider Clean Look which is purely mechanical — no products at all. Let me know what feels right.",keyPoints:["Respect their concern","Explain what Preen actually is","Offer to skip Preen","Offer Clean Look as chemical-free alternative"]},
  {id:64,category:"Service Knowledge",service:"Garden Bed Maintenance",type:"mc",question:"Both bed plans run during what visits?",options:["Separate dedicated visits","Regular weekly mowing visits","Monthly standalone visits","Spring and fall only"],answer:1,explanation:"Built into regular weekly mowing visits."},
  {id:65,category:"Tier Differences",service:"Garden Bed Maintenance",type:"mc",question:"For the most thorough, long-lasting weed control, which plan?",options:["Clean Look — covers more area","Estate Detail — hand-pulling + Preen for lasting results","Either — equal prevention","Neither — need herbicide service"],answer:1,explanation:"Estate Detail = hand-pulling + Preen. Most thorough."},
  {id:66,category:"Service Knowledge",service:"Garden Bed Maintenance",type:"mc",question:"If a client isn't on a mowing plan but wants bed maintenance, what standalone option exists?",options:["Clean Look Plan","One-Time Weeding (no plan required)","Estate Detail Plan","No option exists"],answer:1,explanation:"One-Time Weeding is standalone — no mowing plan required."},
  {id:67,category:"Scenario",service:"Garden Bed Maintenance",type:"scenario",question:"Client asks: \"What's the benefit of Preen? Why does Estate Detail include it?\"",answer:"Preen stops new weed seeds from sprouting. So while hand-pulling handles existing weeds, Preen prevents new ones from popping up. Together they're a great one-two punch — clean beds that stay cleaner longer between visits.",keyPoints:["Preen prevents new weeds from sprouting","Hand-pulling handles existing weeds","Together = 'one-two punch'","Beds stay cleaner longer"]},
  {id:68,category:"Service Knowledge",service:"Garden Bed Maintenance",type:"mc",question:"Clean Look Plan was introduced in which season?",options:["2023","2024","2025","2026"],answer:2,explanation:"New 2025 season."},
  {id:69,category:"Tier Differences",service:"Garden Bed Maintenance",type:"mc",question:"A heavily wooded property with lots of bed area would benefit more from which plan?",options:["Clean Look — covers more ground faster","Estate Detail — thorough hand-pulling prevents overwhelming regrowth","Neither — need full landscaping","Both handle heavy properties equally"],answer:1,explanation:"Heavy weed environments benefit from Estate Detail's thorough approach."},
  {id:70,category:"Scenario",service:"Garden Bed Maintenance",type:"scenario",question:"Client asks: \"Why can't I get bed maintenance without a mowing plan? I mow myself.\"",answer:"Bed maintenance is built into our weekly mowing visits — keeps pricing efficient and service consistent. Without weekly visits, we can't deliver that quality. But we have standalone options: one-time weeding, bed resets, and mulch all work without a mowing plan. Could also consider having us handle mowing too — then everything's covered.",keyPoints:["Built into weekly visits","Requires regular presence","Offer standalone alternatives","Could pitch mowing plan"]},
  {id:71,category:"Service Knowledge",service:"Garden Bed Maintenance",type:"mc",question:"Garden Bed Maintenance runs during which season?",options:["March–October","Spring through fall (with mowing)","Summer only","Year-round"],answer:1,explanation:"Concurrent with mowing season."},
  {id:72,category:"Service Knowledge",service:"Garden Bed Maintenance",type:"mc",question:"How are bed sizes estimated?",options:["Precise measurement","Yards of mulch needed as proxy, eyeballed on-site","Client provides measurements","Satellite imagery"],answer:1,explanation:"Mulch yardage as proxy, eyeballed on-site."},
  {id:73,category:"Service Knowledge",service:"Mulch Installation",type:"mc",question:"What's included in Mulch Installation?",options:["Delivery, installation, and new bed creation","Delivery, installation, bed edging, and complimentary Preen","Delivery only — installation extra","Mulch and garden redesign"],answer:1,explanation:"Delivery, installation, bed edging, and Preen."},
  {id:74,category:"Service Knowledge",service:"Mulch Installation",type:"mc",question:"What is NOT included in Mulch Installation?",options:["Bed edging","Preen application","New bed creation or reclaiming undefined areas","Even depth spread"],answer:2,explanation:"Does NOT include new bed creation, reclaiming areas, or turf removal."},
  {id:75,category:"Service Knowledge",service:"Mulch Installation",type:"mc",question:"What type of mulch does Amigos install?",options:["Red dyed","Natural dark brown","Cedar chips","Client's choice"],answer:1,explanation:"Natural dark brown mulch."},
  {id:76,category:"Scenario",service:"Mulch Installation",type:"scenario",question:"Client asks: \"What exactly is included when you guys do mulch?\"",answer:"Everything: we deliver natural dark brown mulch, install it at even depth across your existing beds, edge along the borders for a clean defined look, and apply Preen to help prevent new weeds. Full package — you just say yes and we handle the rest.",keyPoints:["Delivery and installation","Even depth spread","Bed edging","Preen application","Existing beds only"]},
  {id:77,category:"Service Knowledge",service:"Mulch Installation",type:"mc",question:"Can Amigos create new flower beds as part of mulch service?",options:["Yes — included","No — existing beds only","Only small areas","Only during spring"],answer:1,explanation:"Existing beds only. No new bed creation, turf removal, or expansion."},
  {id:78,category:"Scenario",service:"Mulch Installation",type:"scenario",question:"Client wants to expand flower beds AND get mulch.",answer:"Our mulch service refreshes existing beds — delivery, installation, edging, and Preen. Creating new beds or expanding existing ones isn't part of that scope. You'd need bed creation done separately first. Once new beds exist, we can absolutely mulch them.",keyPoints:["Mulch covers existing beds only","No new bed creation","Bed creation first, then mulch","Be clear about scope"]},
  {id:79,category:"Scenario",service:"Mulch Installation",type:"scenario",question:"Client wants to mulch over weedy beds.",answer:"Mulch alone won't fix a weed problem — they'll push right through. I'd recommend a Bed Reset first to clear everything out, then mulch with Preen to prevent regrowth. That way the mulch holds up and looks good long-term.",keyPoints:["Don't mulch over weeds","Bed Reset first","Then mulch with Preen","Explain why order matters"]},
  {id:80,category:"Service Knowledge",service:"Mulch Installation",type:"mc",question:"How is mulch yardage estimated?",options:["Precise measurement","Eyeballed on-site by crew","Client estimates","Property records"],answer:1,explanation:"Eyeballed on-site."},
  {id:81,category:"Service Knowledge",service:"Mulch Installation",type:"mc",question:"Is bed edging included with mulch or extra?",options:["Always included","Always extra","Only for large jobs","Only with Property Plans"],answer:0,explanation:"Included with mulch installation."},
  {id:82,category:"Service Knowledge",service:"Mulch Installation",type:"mc",question:"Mulch Installation requires a mowing plan?",options:["Yes","No — standalone one-time service","Only for large properties","Only for Property Plan clients"],answer:1,explanation:"Standalone — no mowing plan needed."},
  {id:83,category:"Scenario",service:"Mulch Installation",type:"scenario",question:"Client asks about tree rings with mulch.",answer:"We'll mulch existing tree rings that are already established. Creating new ones involves cutting turf and defining the area, which is outside our mulch scope. Once they exist, we handle them like any other bed.",keyPoints:["Existing tree rings: yes","New tree ring creation: no","Different scope — turf removal needed"]},
  {id:84,category:"Scenario",service:"Mulch Installation",type:"scenario",question:"Client asks: \"How many yards of mulch do I need?\"",answer:"We estimate on-site — our crew eyeballs the beds and figures out the right amount. Most standard suburban homes are in the 3 to 8 yard range, larger properties more. We can get you a quote once we see the property.",keyPoints:["Estimated on-site","General ranges for context","Don't estimate over the phone","Offer to quote after seeing property"]},
  {id:85,category:"Service Knowledge",service:"Mulch Installation",type:"mc",question:"What does the Preen application with mulch do?",options:["Kills existing weeds","Prevents new weed seeds from germinating through the mulch","Fertilizes soil","Keeps mulch color from fading"],answer:1,explanation:"Prevents new weed seeds from germinating."},
  {id:86,category:"Scenario",service:"Mulch Installation",type:"scenario",question:"Client asks: \"Should I do a bed reset before mulch?\"",answer:"Depends on bed condition. Heavy weeds or debris? Reset first, then mulch. Clean beds just needing freshening up? Mulch alone is perfect. The edging and Preen that come with it will give everything a polished look. Mulch alone doesn't fix underlying weed problems — they push through.",keyPoints:["Depends on bed condition","Heavy weeds = reset first","Clean beds = mulch alone fine","Mulch doesn't solve existing weeds"]},
  {id:87,category:"Service Knowledge",service:"Mulch Installation",type:"mc",question:"What does 'existing beds only' mean?",options:["Only beds with current mulch","Clearly defined beds that already exist — no new beds, no turf removal","Only front yard","Only beds Amigos installed"],answer:1,explanation:"Existing, clearly defined beds. No new bed creation or expansion."},
  {id:88,category:"Service Knowledge",service:"Mulch Installation",type:"mc",question:"Mulch Installation is what job type?",options:["Recurring","One-time","Add-on","Monthly"],answer:1,explanation:"One-time service."},
  {id:89,category:"Service Knowledge",service:"Shrub & Bush Shaping",type:"mc",question:"What does Shrub & Bush Shaping involve?",options:["Tree pruning and removal","Professional trimming from ground level using handheld tools","Chemical growth inhibitor","Landscape redesign"],answer:1,explanation:"Professional trimming using handheld tools from ground level. No tree work."},
  {id:90,category:"Tier Differences",service:"Shrub & Bush Shaping",type:"mc",question:"How many visits does Annual Shaping include?",options:["1","2","4","6"],answer:0,explanation:"One visit per year."},
  {id:91,category:"Tier Differences",service:"Shrub & Bush Shaping",type:"mc",question:"How many visits does Bi-Annual Shaping include?",options:["1","2","4","6"],answer:1,explanation:"Two visits per year."},
  {id:92,category:"Tier Differences",service:"Shrub & Bush Shaping",type:"mc",question:"How many visits does Premium Managed Shaping include?",options:["2","4","~6 as-needed","12 monthly"],answer:2,explanation:"Approximately 6 as-needed visits per season."},
  {id:93,category:"Tier Differences",service:"Shrub & Bush Shaping",type:"mc",question:"Which trimming tier requires a mowing plan?",options:["Annual","Bi-Annual","Premium Managed","All three"],answer:2,explanation:"Only Premium Managed requires a mowing plan."},
  {id:94,category:"Service Knowledge",service:"Shrub & Bush Shaping",type:"mc",question:"Does Shrub & Bush Shaping include tree work?",options:["Yes — all trees and shrubs","Only small ornamental trees","No — ground level, handheld tools only","Only under 10 feet"],answer:2,explanation:"Ground level only, handheld tools. No tree work."},
  {id:95,category:"Scenario",service:"Shrub & Bush Shaping",type:"scenario",question:"Client says bushes grow too fast for one annual trim.",answer:"Bi-Annual gives two visits — first after spring growth, second later in season. If you want them always looking sharp, Premium Managed is ongoing as-needed trimming, roughly 6 visits. Premium requires a mowing plan since crews handle it during regular visits.",keyPoints:["Bi-Annual: 2 visits/year","Premium Managed: ~6 ongoing visits","Premium requires mowing plan","Recommend based on growth rate"]},
  {id:96,category:"Scenario",service:"Shrub & Bush Shaping",type:"scenario",question:"Client asks to trim their trees too.",answer:"Our trimming is ground-level work with handheld tools — we don't do tree trimming or removal. For that you'd want a certified arborist. But shrubs, hedges, bushes — we've got you covered.",keyPoints:["No tree work","Ground level only","Redirect to arborist","Confirm what we CAN do"]},
  {id:97,category:"Tier Differences",service:"Shrub & Bush Shaping",type:"mc",question:"Key benefit of Premium Managed over Bi-Annual?",options:["Different equipment","Bushes trimmed on ongoing as-needed basis — never look overgrown","Includes tree work","Uses growth retardants"],answer:1,explanation:"Ongoing as-needed = consistently shaped, never overgrown."},
  {id:98,category:"Scenario",service:"Shrub & Bush Shaping",type:"scenario",question:"Client asks: \"What's the difference between your three bush trimming options?\"",answer:"Annual is one visit per year — good for slow growers. Bi-Annual is two visits — recommended for faster-growing landscapes. Premium Managed is ongoing as needed, roughly 6 visits per season — bushes always look perfect. Premium requires a mowing plan since our crew handles it during visits. For most homes, Bi-Annual is the sweet spot.",keyPoints:["Annual: 1 visit, slow growers","Bi-Annual: 2 visits, most popular","Premium: ~6 visits, always looks perfect","Premium requires mowing plan"]},
  {id:99,category:"Tier Differences",service:"Shrub & Bush Shaping",type:"mc",question:"Can a client without a mowing plan get Annual or Bi-Annual?",options:["No — all require mowing","Yes — only Premium Managed requires mowing","Only Annual","Need at least bed maintenance"],answer:1,explanation:"Annual and Bi-Annual are standalone. Only Premium Managed requires mowing."},
  {id:100,category:"Service Knowledge",service:"Shrub & Bush Shaping",type:"mc",question:"What does 'ground level only' mean?",options:["Only trim at ground level","Work from ground with handheld tools — no ladders, climbing, or overhead work","Only bushes under 3 feet","Crew stays on flat ground"],answer:1,explanation:"Ground level, handheld tools. No ladders, climbing, or overhead work."},
  {id:101,category:"Scenario",service:"Shrub & Bush Shaping",type:"scenario",question:"Client on mowing plan says bushes look terrible between trims.",answer:"Since you're on a mowing plan, you're set for Premium Managed Shaping. Instead of big trims once or twice a year, our crew handles bushes on an ongoing basis — trimming as needed. Roughly 6 visits, built into your mowing visits. Bushes stay consistently shaped all season.",keyPoints:["Recommend Premium Managed (they have mowing plan)","Ongoing vs periodic trimming","Built into existing visits","Consistently maintained"]},
  {id:102,category:"Service Knowledge",service:"Shrub & Bush Shaping",type:"mc",question:"Shrub & Bush Shaping is what job type?",options:["Recurring only","One-time only","Both (one-time or recurring)","Add-on only"],answer:2,explanation:"Can be one-time (Annual, Bi-Annual) or recurring (Premium Managed)."},
  {id:103,category:"Service Knowledge",service:"Perennial Flower Pruning",type:"mc",question:"What is Perennial Flower Pruning?",options:["Trimming shrubs and trees","Seasonal pruning of perennial flowers — typically spring and fall","Removing dead annuals","Planting new perennials"],answer:1,explanation:"Seasonal pruning at appropriate times — spring and/or fall."},
  {id:104,category:"Service Knowledge",service:"Perennial Flower Pruning",type:"mc",question:"Perennial Flower Pruning is classified as?",options:["Standalone","Add-on","Included with mowing","Part of bed maintenance"],answer:1,explanation:"It's an add-on service."},
  {id:105,category:"Service Knowledge",service:"Perennial Flower Pruning",type:"mc",question:"Does it include shrub or tree trimming?",options:["Yes — all plants","Only small shrubs","No — perennial flowers only","Only near perennials"],answer:2,explanation:"Perennial flowers only. Shrubs and trees are separate."},
  {id:106,category:"Service Knowledge",service:"Perennial Flower Pruning",type:"mc",question:"How many sessions per year?",options:["1","2 (spring + fall)","4","Monthly"],answer:1,explanation:"Typically 2: spring and fall cut-back."},
  {id:107,category:"Service Knowledge",service:"Leaf Care",type:"mc",question:"Recurring Leaf Care requires what?",options:["Garden Bed Maintenance","A mowing plan","Snow Removal","Spring Cleanup"],answer:1,explanation:"Requires active mowing plan."},
  {id:108,category:"Tier Differences",service:"Leaf Care",type:"mc",question:"What does Standard Leaf Care include?",options:["Leaves hauled away every visit","Leaves mulched into turf weekly + deep cleanup at season end","Full property cleared every visit","One cleanup at end only"],answer:1,explanation:"Mulched into turf weekly, deep cleanup at end."},
  {id:109,category:"Tier Differences",service:"Leaf Care",type:"mc",question:"What does Pristine Leaf Care include?",options:["Mulched weekly","Collected and hauled away from lawn and hardscapes every visit + comprehensive final cleanup","Same as Standard with extra cleanup","Beds cleared every visit"],answer:1,explanation:"Hauled away from lawn and hardscapes every visit + comprehensive final cleanup."},
  {id:110,category:"Tier Differences",service:"Leaf Care",type:"mc",question:"What makes Estate Leaf Care different from Pristine?",options:["Just a bigger version","Clears lawn, hardscapes, AND all flower beds every visit","Includes snow removal","Runs through December"],answer:1,explanation:"Completely clears lawn, hardscapes, AND all beds every visit. Most comprehensive."},
  {id:111,category:"Scenario",service:"Leaf Care",type:"scenario",question:"Client asks about three leaf care levels.",answer:"Standard mulches leaves into your turf weekly — controls buildup and recycles nutrients. Deep cleanup at season end. Pristine collects and hauls away from lawn and hardscapes every visit, plus comprehensive final cleanup. Estate is the top — clears everything every visit including all flower beds. Property stays immaculate all fall. If you don't want leaves everywhere, Pristine or Estate is where you want to be.",keyPoints:["Standard: mulch weekly + end cleanup","Pristine: haul-away lawn/hardscapes + final cleanup","Estate: everything including beds every visit","Match expectation to tier"]},
  {id:112,category:"Tier Differences",service:"Leaf Care",type:"mc",question:"Which tier clears flower beds every visit?",options:["Standard","Pristine","Estate","All three"],answer:2,explanation:"Only Estate clears beds every visit."},
  {id:113,category:"Service Knowledge",service:"Leaf Care",type:"mc",question:"Is mowing billed separately from Leaf Care?",options:["Included","Yes — mowing is base, Leaf Care is add-on","Only with Estate","Mowing stops for leaf care"],answer:1,explanation:"Mowing billed separately as base service."},
  {id:114,category:"Scenario",service:"Leaf Care",type:"scenario",question:"Client wants just one cleanup at end of fall, not recurring.",answer:"That's our One-Time Property Cleanup — single comprehensive visit. Choose Nutrient Standard (shredded, returned to soil) or Pristine Standard (hauled away). Good option if you're okay with buildup during the season and just want a clean finish.",keyPoints:["Redirect to One-Time Property Cleanup","Two tiers: Nutrient vs Pristine","Single visit alternative","Leaves accumulate during season"]},
  {id:115,category:"Scenario",service:"Leaf Care",type:"scenario",question:"Client on Standard says neighbor's trees dump tons of leaves.",answer:"For heavy leaf volume, Pristine or Estate may be better. Pristine hauls away from lawn and hardscapes every visit instead of mulching. Estate adds bed clearing too. Our pricing factors in leaf volume already, so heavy properties have that accounted for. Want to look at upgrading?",keyPoints:["Suggest Pristine or Estate upgrade","Explain the difference","Leaf volume multiplier already accounts for coverage","Offer to quote"]},
  {id:116,category:"Tier Differences",service:"Leaf Care",type:"mc",question:"Progression from least to most comprehensive?",options:["Standard → Estate → Pristine","Pristine → Standard → Estate","Standard → Pristine → Estate","Estate → Pristine → Standard"],answer:2,explanation:"Standard → Pristine → Estate."},
  {id:117,category:"Service Knowledge",service:"Leaf Care",type:"mc",question:"Standard mulching benefits?",options:["Faster for crews","Returns nutrients to soil","Prevents weed growth","Eliminates final cleanup need"],answer:1,explanation:"Mulched leaves return nutrients to soil."},
  {id:118,category:"Scenario",service:"Leaf Care",type:"scenario",question:"Client on Pristine asks why there are leaves in beds.",answer:"Pristine focuses on lawn and hardscapes during weekly visits. Beds get addressed in the final cleanup. If you want beds cleared every single visit throughout the season, that's Estate — the most comprehensive tier. Lawn, hardscapes, and all beds every week.",keyPoints:["Pristine: lawn + hardscapes weekly, beds at final cleanup","Estate: everything including beds every visit","Explain scope clearly","Offer Estate upgrade"]},
  {id:119,category:"Scenario",service:"Leaf Care",type:"scenario",question:"Budget client choosing between Standard and Pristine.",answer:"Standard mulches leaves weekly and does a thorough cleanup at the end. Some leaf coverage between visits, but controlled. Pristine hauls away from lawn and hardscapes every visit — property looks cleaner week-to-week. Depends on how much visible leaves bother you. If you're okay with some natural coverage and like the soil health benefit, Standard is solid. If you want it looking sharp every week, Pristine is worth it.",keyPoints:["Standard: affordable, some weekly coverage","Pristine: cleaner consistently, costs more","Standard has soil health benefit","Choose based on tolerance for leaves"]},
  {id:120,category:"Service Knowledge",service:"Leaf Care",type:"mc",question:"Does mowing stop during leaf care season?",options:["Yes — leaf care replaces mowing","No — mowing continues alongside through end of season","Switches to bi-weekly","Only with Estate"],answer:1,explanation:"Mowing continues alongside leaf care."},
  {id:121,category:"Scenario",service:"Leaf Care",type:"scenario",question:"Client not on mowing plan asks about leaf care.",answer:"Recurring Leaf Care requires a mowing plan since it's built into weekly visits. But we have the One-Time Property Cleanup — a single comprehensive visit. Nutrient or Pristine tier. Or I could also build you a plan that includes mowing and leaf care together.",keyPoints:["Recurring requires mowing plan","Redirect to One-Time Cleanup","Could also pitch mowing plan"]},
  {id:122,category:"Service Knowledge",service:"Leaf Care",type:"mc",question:"What does Pristine's final cleanup include beyond Standard's?",options:["Identical","Comprehensively clears all landscape beds","Gutter cleaning","Roof clearing"],answer:1,explanation:"Pristine's final is comprehensive, also clearing all landscape beds."},
  {id:123,category:"Tier Differences",service:"Leaf Care",type:"mc",question:"Client wants entire property leaf-free all fall. Which tier?",options:["Standard","Pristine","Estate","Standard + separate bed cleanup"],answer:2,explanation:"Estate = full property cleared every visit."},
  {id:124,category:"Service Knowledge",service:"Leaf Care",type:"mc",question:"Leaf volume rating (1-5) measures what?",options:["Number of trees","Difficulty based on leaf coverage amount","Distance to haul","Leaf type"],answer:1,explanation:"Reflects how much leaf coverage the property receives (1=lightest, 5=heaviest)."},
  {id:125,category:"Service Knowledge",service:"Leaf Care",type:"mc",question:"Leaf Care runs during which visits?",options:["Separate dedicated visits","Regular weekly mowing visits","Monthly standalone","Weekend only"],answer:1,explanation:"Runs during regular weekly mowing visits."},
  {id:126,category:"Scenario",service:"Leaf Care",type:"scenario",question:"Client asks: \"Is recurring leaf care worth it or should I just do the one-time cleanup?\"",answer:"Recurring manages leaves weekly so your property stays clean all fall. One-time means leaves accumulate and we do one big clean at the end — costs less but you live with coverage for weeks. If you care about weekly appearance or entertain, recurring is worth it. If buildup doesn't bother you, one-time saves money.",keyPoints:["Recurring: clean all fall","One-time: accumulate, one big clean","One-time costs less","Choose based on lifestyle and tolerance"]},
  {id:127,category:"Service Knowledge",service:"One-Time Property Cleanup",type:"mc",question:"One-Time Property Cleanup is the alternative to?",options:["Spring Cleanup","Garden Bed Maintenance","Recurring Leaf Care","Mowing"],answer:2,explanation:"Single-visit alternative to recurring Leaf Care."},
  {id:128,category:"Tier Differences",service:"One-Time Property Cleanup",type:"mc",question:"Two tiers for One-Time Property Cleanup?",options:["Standard and Premium","Nutrient Standard and Pristine Standard","Basic and Complete","Clean Look and Estate Detail"],answer:1,explanation:"Nutrient (return to soil) and Pristine (haul away)."},
  {id:129,category:"Service Knowledge",service:"One-Time Property Cleanup",type:"mc",question:"Requires a mowing plan?",options:["Yes","No — standalone one-time","Only Pristine","Only Property Plan clients"],answer:1,explanation:"Standalone — no mowing plan."},
  {id:130,category:"Service Knowledge",service:"One-Time Property Cleanup",type:"mc",question:"Typically performed when?",options:["March–April","July–August","October–December","January–February"],answer:2,explanation:"Typically Oct–Dec."},
  {id:131,category:"Service Knowledge",service:"Bed Reset / Garden Cleanup",type:"mc",question:"What is a Bed Reset?",options:["Installing new plants","Thorough one-time cleanup — removes weeds, debris, dead plants, brings beds to clean baseline","Chemical weed killer","Replacing mulch"],answer:1,explanation:"Thorough cleanup bringing beds to a clean, maintainable baseline."},
  {id:132,category:"Service Knowledge",service:"Bed Reset / Garden Cleanup",type:"mc",question:"Bed Reset is commonly done before?",options:["Spring Cleanup and Aeration","Mulch Installation or starting a bed maintenance plan","Snow Removal","Overseeding"],answer:1,explanation:"Common prerequisite before mulch or maintenance plan."},
  {id:133,category:"Service Knowledge",service:"One-Time Weeding",type:"mc",question:"What is One-Time Weeding?",options:["Full garden redesign","Single visit to clear weeds — basic (trimmer) or detail (hand-pull)","Chemical herbicide","Weed barrier fabric"],answer:1,explanation:"Single visit, basic or detail, no commitment."},
  {id:134,category:"Service Knowledge",service:"Bed Edging",type:"mc",question:"What does Bed Edging do?",options:["Installs metal edging","Defines and restores clean borders between lawn and beds","Cuts new beds from lawn","Removes existing edging"],answer:1,explanation:"Defines and restores clean borders."},
  {id:135,category:"Service Knowledge",service:"Bed Edging",type:"mc",question:"Is Bed Edging included with Mulch or separate?",options:["Separate always","Typically included with Mulch, also available standalone","Only for large properties","Only with Estate Detail"],answer:1,explanation:"Included with mulch, also standalone."},
  {id:136,category:"Scenario",service:"One-Time Bed Services",type:"scenario",question:"New homeowner: beds are a mess, wants cleanup + mulch + ongoing maintenance.",answer:"Step 1: Bed Reset to clear weeds, dead plants, debris — clean baseline. Step 2: Mulch — fresh mulch, edging, Preen. Step 3: Ongoing maintenance — Clean Look (affordable, mechanical) or Estate Detail (thorough, hand-pull + Preen). Maintenance runs with mowing. Each quoted separately, done in order.",keyPoints:["Bed Reset first","Then Mulch","Then recurring maintenance","Maintenance requires mowing plan","Each quoted separately"]},
  {id:137,category:"Service Knowledge",service:"One-Time Bed Services",type:"mc",question:"Do One-Time Bed Services require a mowing plan?",options:["Yes — all","No — all standalone","Only Bed Reset","Only Bed Edging"],answer:1,explanation:"All standalone — no mowing plan required."},
  {id:138,category:"Scenario",service:"One-Time Bed Services",type:"scenario",question:"Client just wants weeds pulled once — nothing ongoing.",answer:"One-Time Weeding — single visit, no commitment. Basic uses a string trimmer (quick, roots stay) or detail is hand-pulled from root (more thorough). If you want ongoing care later, we have maintenance plans too.",keyPoints:["One-Time Weeding","Basic vs detail options","No commitment","Mention maintenance as future option"]},
  {id:139,category:"Service Knowledge",service:"One-Time Bed Services",type:"mc",question:"What are One-Time Bed Services described as?",options:["Add-ons to plans","Stand-alone jobs outside recurring plans","Emergency services","Property Plan only"],answer:1,explanation:"Stand-alone jobs to address bed condition outside recurring plans."},
  {id:140,category:"Service Knowledge",service:"One-Time Weeding",type:"mc",question:"Difference between 'basic' and 'detail' One-Time Weeding?",options:["Front yard vs full property","Basic uses trimmer (roots stay); detail is hand-pulled from root","One visit vs two","Chemical vs organic"],answer:1,explanation:"Basic = trimmer, roots stay. Detail = hand-pull from root."},
  {id:141,category:"Scenario",service:"One-Time Bed Services",type:"scenario",question:"Client asks: \"What's the difference between Bed Reset and One-Time Weeding?\"",answer:"Bed Reset is comprehensive — clears weeds, dead plants, debris, everything. Brings beds all the way back to a clean baseline. Usually done before mulch or starting maintenance. One-Time Weeding is lighter — just clearing weed growth specifically. If beds need a 'starting over' level of work, that's a reset. If they just need weeds knocked down, that's one-time weeding.",keyPoints:["Reset: comprehensive, everything cleared","Weeding: just weed removal","Reset = 'starting over'; Weeding = 'touch up'","Reset is prerequisite for mulch/maintenance"]},
  {id:142,category:"Service Knowledge",service:"One-Time Bed Services",type:"mc",question:"Which service is the most common prerequisite before mulch?",options:["One-Time Weeding","Bed Edging","Bed Reset / Garden Cleanup","Perennial Pruning"],answer:2,explanation:"Bed Reset is the common prerequisite."},
  {id:143,category:"Service Knowledge",service:"One-Time Bed Services",type:"mc",question:"What category do these services fall under?",options:["Garden Bed Maintenance","One-Time Bed Services","Seasonal Cleanups","Mulch Installation"],answer:1,explanation:"One-Time Bed Services — standalone."},
  {id:144,category:"Service Knowledge",service:"Bed Edging",type:"mc",question:"Bed Edging can be booked how?",options:["Only with mulch","Only with Property Plan","Standalone or paired","Only with Estate Detail"],answer:2,explanation:"Standalone or paired with other services."},
  {id:145,category:"Service Knowledge",service:"Snow Removal",type:"mc",question:"Standard Snow Removal triggers at?",options:["Any trace","~1 inch","~2 inches","~4 inches"],answer:2,explanation:"Standard: ~2 inches."},
  {id:146,category:"Tier Differences",service:"Snow Removal",type:"mc",question:"Premium Snow Removal triggers at?",options:["Any trace","~1 inch","~2 inches","~3 inches"],answer:1,explanation:"Premium: ~1 inch."},
  {id:147,category:"Tier Differences",service:"Snow Removal",type:"mc",question:"Zero Tolerance triggers at?",options:["~1 inch","~0.5 inch","Any accumulation (trace)","Only ice events"],answer:2,explanation:"Any accumulation — property stays clear at all times."},
  {id:148,category:"Service Knowledge",service:"Snow Removal",type:"mc",question:"Visits per qualifying snow event?",options:["1","2","3","Unlimited"],answer:3,explanation:"Unlimited visits per event across all tiers."},
  {id:149,category:"Service Knowledge",service:"Snow Removal",type:"mc",question:"Snow Removal covers what areas?",options:["Entire property","Designated driveways and walkways","Only driveway","Driveway, walkways, and roof"],answer:1,explanation:"Designated driveways and walkways."},
  {id:150,category:"Service Knowledge",service:"Snow Removal",type:"mc",question:"Service hours for Snow Removal?",options:["Business hours","Extended (6am-10pm)","24/7","On-call"],answer:2,explanation:"All tiers: 24/7."},
  {id:151,category:"Tier Differences",service:"Snow Removal",type:"mc",question:"Premium offers what beyond a lower trigger?",options:["Sidewalk shoveling","Priority dispatch and earlier response window","Salt included","Roof clearing"],answer:1,explanation:"Priority dispatch and earlier response window."},
  {id:152,category:"Scenario",service:"Snow Removal",type:"scenario",question:"Client asks about Standard vs Premium snow removal.",answer:"Standard triggers at about 2 inches — 24/7, unlimited visits. Premium triggers at about 1 inch and you get priority dispatch with earlier response time. Both unlimited visits per event. Premium is for people who need it cleared sooner or at a lower accumulation — early commuters, safety concerns, etc.",keyPoints:["Standard: ~2 inch, 24/7, unlimited","Premium: ~1 inch, priority dispatch","Both unlimited","Choose based on schedule and safety needs"]},
  {id:153,category:"Scenario",service:"Snow Removal",type:"scenario",question:"Client with elderly parents — cannot have any snow, fall risk.",answer:"Zero Tolerance — triggers at any trace, highest priority, property stays completely clear at all times. Exactly designed for safety-critical situations like yours.",keyPoints:["Zero Tolerance immediately","Any trace trigger","Highest priority","Validate safety concern"]},
  {id:154,category:"Scenario",service:"Snow Removal",type:"scenario",question:"Client can handle light snow themselves, only wants help for big storms.",answer:"Standard is perfect — triggers at about 2 inches, so light dustings don't activate a visit. Once it hits that level, we're out 24/7, unlimited visits. Seasonal rate, not per-visit charges.",keyPoints:["Standard: ~2 inch trigger fits","Light snow won't trigger visits","Unlimited for qualifying events","Seasonal rate"]},
  {id:155,category:"Scenario",service:"Snow Removal",type:"scenario",question:"Client asks: \"If it snows 3 times in one day, do you come back each time?\"",answer:"We come back as many times as needed — unlimited visits per event, 24/7. If it keeps accumulating, we keep coming back.",keyPoints:["Unlimited visits per event","Come back as needed","24/7","No visit limits"]},
  {id:156,category:"Service Knowledge",service:"Salt Treatment",type:"mc",question:"What is Salt Treatment?",options:["Standalone winter service","Add-on: ice-melt applied after snow clearing","Pre-treatment before snowfall","Included with all tiers"],answer:1,explanation:"Add-on: ice-melt after clearing for traction and icing reduction."},
  {id:157,category:"Service Knowledge",service:"Salt Treatment",type:"mc",question:"Is Salt included with Snow Removal?",options:["Included with all tiers","Included with Premium/Zero Tolerance only","Separate add-on for all tiers","Only with Zero Tolerance"],answer:2,explanation:"Separate add-on for any tier."},
  {id:158,category:"Tier Differences",service:"Snow Removal",type:"mc",question:"Correct order least to most comprehensive?",options:["Premium → Standard → Zero Tolerance","Standard → Premium → Zero Tolerance","Zero Tolerance → Premium → Standard","Standard → Zero Tolerance → Premium"],answer:1,explanation:"Standard → Premium → Zero Tolerance."},
  {id:159,category:"Scenario",service:"Snow Removal",type:"scenario",question:"Client asks what Zero Tolerance means.",answer:"It's our top tier — triggers at any trace of snow. As soon as anything sticks, we're dispatched. Highest priority, 24/7. Your property never has snow on it. Popular for safety concerns or people who don't want to deal with any snow at all.",keyPoints:["Any trace trigger","Highest priority","Property always clear","No judgment — explain clearly"]},
  {id:160,category:"Tier Differences",service:"Snow Removal",type:"mc",question:"All three tiers share which features?",options:["Same trigger","24/7, unlimited visits, driveways and walkways","Priority dispatch","Salt included"],answer:1,explanation:"All: 24/7, unlimited visits, designated driveways and walkways."},
  {id:161,category:"Service Knowledge",service:"Snow Removal",type:"mc",question:"Snow Removal is what job type?",options:["One-time","Recurring (seasonal)","As-needed per storm","Monthly"],answer:1,explanation:"Recurring seasonal service."},
  {id:162,category:"Scenario",service:"Snow Removal",type:"scenario",question:"Client asks: \"Do you salt after you plow?\"",answer:"Salt Treatment is an optional add-on — after clearing, we apply ice-melt to walkways and driveways for traction and icing reduction. Not automatic — it's available with any Snow Removal tier. Most clients with safety concerns add it.",keyPoints:["Salt is an add-on, not automatic","Applied after clearing","Available with any tier","Common for safety-focused clients"]},
  {id:163,category:"Tier Differences",service:"Snow Removal",type:"mc",question:"Client who works from home — reliable but not urgent. Which tier?",options:["Zero Tolerance","Standard — reasonable for regular needs","Premium — only for ice","Don't need service"],answer:1,explanation:"Standard is appropriate for regular needs."},
  {id:164,category:"Tier Differences",service:"Snow Removal",type:"mc",question:"Client leaving at 5 AM needing driveway clear early. Which tier?",options:["Standard","Premium — priority dispatch, earlier response","Zero Tolerance only","Custom arrangement needed"],answer:1,explanation:"Premium's priority dispatch and earlier response window."},
  {id:165,category:"Service Knowledge",service:"Snow Removal",type:"mc",question:"Snow Removal season runs?",options:["December–February","First snowfall through March 31","November–April","During declared emergencies"],answer:1,explanation:"First qualifying snowfall through March 31."},
  {id:166,category:"Service Knowledge",service:"Property Plan",type:"mc",question:"Two ways clients can book services?",options:["Monthly subscription or pay-per-visit","As-Needed or Property Plan (membership)","Residential or commercial","DIY or full-service"],answer:1,explanation:"As-Needed (individual jobs) or Property Plan (custom membership)."},
  {id:167,category:"Service Knowledge",service:"Property Plan",type:"mc",question:"How is a Property Plan billed?",options:["Lump sum","Per service completed","12 monthly installments","Quarterly"],answer:2,explanation:"12 monthly installments."},
  {id:168,category:"Service Knowledge",service:"Property Plan",type:"mc",question:"Pre-pay incentive?",options:["10% discount","1 month free","Free spring cleanup","No incentive"],answer:1,explanation:"Pre-pay full year = 1 month free."},
  {id:169,category:"Service Knowledge",service:"Property Plan",type:"mc",question:"Scheduling benefit for plan members?",options:["Weekend scheduling","Priority scheduling for one-off requests","Same-day guarantee","No benefit"],answer:1,explanation:"Priority scheduling for one-off requests."},
  {id:170,category:"Scenario",service:"Property Plan",type:"scenario",question:"Client asks: \"Why a Property Plan instead of calling when I need something?\"",answer:"Everything pre-scheduled, same monthly payment across 12 months, priority scheduling, and pre-pay gets you a month free. With As-Needed you schedule individually and might not get priority during busy weeks. Plan is set-it-and-forget-it.",keyPoints:["Pre-scheduled for the year","12 even monthly payments","Priority scheduling","Pre-pay = 1 month free","Compare to As-Needed"]},
  {id:171,category:"Scenario",service:"Property Plan",type:"scenario",question:"Client wants mowing, leaf care, and snow. Pitch a plan?",answer:"Absolutely — three recurring services spanning most of the year. Perfect for a Property Plan. One monthly payment, everything pre-scheduled, priority scheduling. Pre-pay the year and get a month free. I'd build a custom plan bundling all three.",keyPoints:["Multiple recurring = ideal plan candidate","One monthly payment","Pre-scheduled and priority","Pre-pay savings"]},
  {id:172,category:"Scenario",service:"Property Plan",type:"scenario",question:"Client just wants mulch and one-time weeding. Push a plan?",answer:"No — both are one-time services, perfect for As-Needed booking. Just quote, schedule, and invoice per job. Plans make sense for recurring services. Leave the door open for future recurring needs.",keyPoints:["No plan needed for one-time services","As-Needed is right fit","Don't push when it doesn't make sense","Leave door open"]},
  {id:173,category:"Service Knowledge",service:"Property Plan",type:"mc",question:"Can clients book any service As-Needed without a plan?",options:["No — some require a plan","Yes — any service individually","Only one-time services","Only under $500"],answer:1,explanation:"Any service can be booked individually."},
  {id:174,category:"Service Knowledge",service:"Property Plan",type:"mc",question:"Which services REQUIRE a mowing plan?",options:["Spring Cleanup and Mulch","Garden Bed Maintenance, Leaf Care, Premium Managed Shaping","All except snow","Only Garden Bed Maintenance"],answer:1,explanation:"Garden Bed Maintenance, Leaf Care, and Premium Managed Shaping."},
  {id:175,category:"Scenario",service:"Property Plan",type:"scenario",question:"Competitor offers one price for everything. Client asks if you can match.",answer:"We build every plan custom to each property — you only pay for what makes sense. One-size-fits-all usually means overpaying or corners being cut. I'd rather build something that fits perfectly.",keyPoints:["Custom-built per property","Pay for what you need","One-size-fits-all = overpaying or corners cut","Position customization as advantage"]},
  {id:176,category:"Scenario",service:"Property Plan",type:"scenario",question:"Client asks how pre-pay discount works.",answer:"Pre-pay the full year upfront and you get one month free — pay 11 months instead of 12. Savings scale with plan size. Everything locked in and done.",keyPoints:["1 month free (pay 11 not 12)","Savings scale with plan size","Everything locked in"]},
  {id:177,category:"Service Knowledge",service:"Property Plan",type:"mc",question:"As-Needed services are invoiced how?",options:["Monthly installments","Per job when completed","Quarterly","Annual lump sum"],answer:1,explanation:"Invoiced per job."},
  {id:178,category:"Scenario",service:"Property Plan",type:"scenario",question:"Client isn't sure about committing to a full year.",answer:"You can start with just mowing and add services anytime. Lots of clients start that way — get comfortable, then layer in bed care, leaf care, snow removal as seasons change. No pressure to do everything upfront.",keyPoints:["Start with mowing only","Add over time","No pressure to commit to everything","Meet them where they are"]},
  {id:179,category:"Service Knowledge",service:"Property Plan",type:"mc",question:"Key advantage of a plan for multi-service clients?",options:["Lower prices per service","Pre-scheduled everything, one monthly payment, priority scheduling","Dedicated crew","Same-day service"],answer:1,explanation:"Pre-scheduled, consistent billing, priority scheduling."},
  {id:180,category:"Service Knowledge",service:"Property Plan",type:"mc",question:"A Property Plan is described as?",options:["Standard contract","Custom plan built around the client's property","One-size-fits-all package","Referral program"],answer:1,explanation:"Custom plan built around the client's property."},
  {id:181,category:"Service Knowledge",service:"General",type:"mc",question:"How many service categories does Amigos have?",options:["5","6","7","8"],answer:3,explanation:"8 categories."},
  {id:182,category:"Service Knowledge",service:"General",type:"mc",question:"Which service specifies 'ground level only'?",options:["Garden Bed Maintenance","Shrub & Bush Shaping","Spring Cleanup","Mulch Installation"],answer:1,explanation:"Shrub & Bush Shaping — ground level, handheld tools, no tree work."},
  {id:183,category:"Service Knowledge",service:"General",type:"mc",question:"Which service does Amigos NOT offer?",options:["Aeration","Irrigation/sprinkler maintenance","Snow removal","Trimming & Pruning"],answer:1,explanation:"Irrigation is not offered."},
  {id:184,category:"Service Knowledge",service:"General",type:"mc",question:"Mulch Installation and Estate Detail both include what?",options:["Fertilizer","Herbicide","Preen weed preventer","Lime"],answer:2,explanation:"Both include Preen."},
  {id:185,category:"Service Knowledge",service:"General",type:"mc",question:"Which is an add-on service (not standalone)?",options:["Spring Aeration","Mulch Installation","Perennial Flower Pruning","Bed Reset"],answer:2,explanation:"Perennial Flower Pruning and Salt Treatment are add-ons."},
  {id:186,category:"Scenario",service:"General",type:"scenario",question:"Client wants 'the full treatment — everything, year-round.' Walk them through it.",answer:"Spring: Cleanup, Aeration + Overseeding. April: weekly mowing (Pristine for cleanest look). Beds: Estate Detail for hand-pulled weeding. Mulch. Bushes: Premium Managed. Perennial pruning. Fall: Leaf Care on Estate — full property cleared every visit. Winter: Snow Removal + Salt. All in a Property Plan, one monthly payment.",keyPoints:["Walk through full seasonal calendar","Premium tiers for full-treatment client","Cover all seasons","Wrap in Property Plan"]},
  {id:187,category:"Scenario",service:"General",type:"scenario",question:"Client asks why some services need a mowing plan.",answer:"Services like bed maintenance, leaf care, and premium trimming are built into our weekly mowing visits — keeps pricing efficient and quality consistent. Plenty of standalone options don't need mowing: mulch, bed resets, weeding, regular trimming, aeration, cleanups.",keyPoints:["Built into weekly visits","Efficient and consistent","Many standalone options exist","Don't lose the client — redirect"]},
  {id:188,category:"Service Knowledge",service:"General",type:"mc",question:"Which services require a mowing plan?",options:["Garden Bed Maintenance + Mulch + Aeration","Garden Bed Maintenance + Leaf Care + Premium Managed Shaping","All recurring services","Only Garden Bed Maintenance"],answer:1,explanation:"Garden Bed Maintenance, Leaf Care, and Premium Managed Shaping."},
  {id:189,category:"Scenario",service:"General",type:"scenario",question:"New client calls in fall. What services are relevant?",answer:"Fall Aeration + Overseeding to strengthen the lawn. Leaf Care — Standard, Pristine, or Estate, or One-Time Cleanup alternative. Snow Removal for winter — three tiers plus salt. Could start mowing for tail end of season, sets them up for next year. Build a plan covering winter into next spring.",keyPoints:["Fall Aeration + Overseeding","Leaf Care options or One-Time Cleanup","Snow Removal approaching","Pitch a plan into next spring"]},
  {id:190,category:"Scenario",service:"General",type:"scenario",question:"Property Plan client calls in August for a season summary.",answer:"Done so far: spring cleanup, aeration, overseeding, weekly mowing since April, bed maintenance, mulch, bush trimming. Coming up: fall aeration in September, leaf care kicks in October through November, snow removal for winter. Fully covered — nothing to schedule.",keyPoints:["Recap completed services","Upcoming: fall aeration, leaf care, snow","Show calendar knowledge","Emphasize hands-off benefit"]},
  {id:191,category:"Service Knowledge",service:"General",type:"mc",question:"General seasonal order of services?",options:["Mulch → Cleanup → Mowing → Snow","Cleanup → Aeration → Mowing → Mulch → Trimming → Leaf Care → Snow","Mowing → Cleanup → Mulch → Snow","Aeration → Cleanup → Snow → Mowing"],answer:1,explanation:"Cleanup → Aeration → Mowing → Mulch → Trimming → Leaf Care → Snow."},
  {id:192,category:"Service Knowledge",service:"General",type:"mc",question:"How many services are 'Recurring only'?",options:["3","4","5","6"],answer:1,explanation:"4: Weekly Lawn Maintenance, Garden Bed Maintenance, Leaf Care, Snow Removal."},
  {id:193,category:"Scenario",service:"General",type:"scenario",question:"Client asks for a ballpark on mowing and basic bed care for a normal suburban home.",answer:"Weekly mowing — Nutrient Standard (clippings recycled) or Pristine (bagged). For beds: Clean Look (affordable, mechanical trimming) or Estate Detail (hand-pulled + Preen). Both bed plans run with mowing. I'd need to see the property for exact numbers, but those are your options. Want me to put together a quote?",keyPoints:["Mowing: Nutrient vs Pristine","Beds: Clean Look vs Estate Detail","Need to see property for pricing","Offer to quote — don't guess numbers"]},
  {id:194,category:"Scenario",service:"General",type:"scenario",question:"Client asks about landscape design, plantings, or hardscaping.",answer:"We focus on maintenance — lawn care, bed care, seasonal services, winter services. We don't do design, new plantings, or hardscaping. For that you'd want a landscape design company. But once new landscaping is installed, we're great at maintaining it.",keyPoints:["We don't offer design, plantings, hardscaping","Be honest","Redirect to design companies","We maintain what's already there"]},
  {id:195,category:"Service Knowledge",service:"General",type:"mc",question:"Which is NOT a service category?",options:["Seasonal Cleanups","Landscape Design & Installation","Winter Services","Trimming & Pruning"],answer:1,explanation:"Landscape Design & Installation is not offered."},
  {id:196,category:"Scenario",service:"General",type:"scenario",question:"Client says competitor claimed returning grass clippings causes thatch and disease.",answer:"That's a common misconception. Finely mulched clippings break down quickly and return nutrients to the soil — research consistently supports this. Our Nutrient Standard is based on that science. If they still prefer a clean look, Pristine bags everything. Both are great options.",keyPoints:["Address misconception confidently","Mulched clippings don't cause thatch","Research supports it","Offer Pristine as alternative","Don't badmouth competitor"]},
  {id:197,category:"Service Knowledge",service:"General",type:"mc",question:"Nutrient vs Pristine naming applies to which services?",options:["All services","Mowing, Spring Cleanup, One-Time Property Cleanup","Only mowing","Only winter"],answer:1,explanation:"Services where material is returned to soil vs hauled away."},
  {id:198,category:"Service Knowledge",service:"General",type:"mc",question:"Which two services both include Preen applications?",options:["Spring Cleanup and Mulch","Mulch Installation and Estate Detail Plan","Clean Look Plan and Spring Cleanup","Leaf Care and Snow Removal"],answer:1,explanation:"Mulch Installation and Estate Detail Plan."},
  {id:199,category:"Service Knowledge",service:"General",type:"mc",question:"Salt Treatment is classified as?",options:["Standalone service","Add-on service","Included with Premium Snow Removal","Free with any plan"],answer:1,explanation:"Add-on service to Snow Removal."},
  {id:200,category:"Scenario",service:"General",type:"scenario",question:"A client asks: \"What's the one service I should start with if I'm new to Amigos?\"",answer:"For most homeowners, weekly mowing is the foundation — it's what we build everything else around. Once you're on a mowing plan, services like bed maintenance and leaf care become available since our crews are already at your property weekly. Start with mowing, see how you like the service, and we can layer in whatever makes sense from there. No pressure to do everything at once.",keyPoints:["Mowing is the foundation","Unlocks other services (bed care, leaf care)","Start there and add over time","Low pressure approach","Build the relationship first"]}
];
